import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest cases — quote with edge inputs
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums for main items
  it("single plain sword (newcomer, first contract) → 100 + 10 first-insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single plain amulet (newcomer, first contract) → 60 + 6 first-insurance + 5 fee = 71 G (rounded up)");
  it.todo("single plain staff (newcomer, first contract) → 80 + 8 first-insurance + 5 fee = 93 G");
  it.todo("single plain potion (newcomer, first contract) → 40 + 4 first-insurance + 5 fee = 49 G");

  // Components — building-block discount
  it.todo("2 runes → base premium 50 G (no block)");
  it.todo("3 runes → base premium 60 G (block applies)");
  it.todo("4 runes → base premium 100 G (no block; block requires exactly 3)");
  it.todo("7 runes → base premium 175 G (no block; 7 = no group of exactly 3 with leftovers)");

  // 'Alike' components — same type, not family
  it.todo("2 runes + 1 moonstone → base premium 75 G (no block, different types)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet → 100 + 60 + 50 (curse on sword only) = 210 G before further modifiers and fee");

  // Modifier thresholds
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword enchantment exactly 5 → high-enchantment surcharge applies");
  it.todo("cursed sword enchantment exactly 5 → both curse and high-enchantment surcharges apply");
  it.todo("sword enchantment 4, not cursed → no surcharge");

  // Rounding in MHPCO's favor
  it.todo("premium 197.5 G → rounded up to 198 G");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("long-standing customer (3 years), 2nd contract, cursed sword ench 7 → 160 G");

  // Quote errors
  it.todo("quote with unknown item type → CLI exits non-zero, writes error to stderr, no results");

  // Claim — standard reimbursement
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
  it.todo("damage to a rune (no enchantment/material), damage 200 G → payout 100 G (200 − 100)");

  // Claim — enchantment threshold and dragon material
  it.todo("dragon sword, ench 8, damage 1000 G → payout 400 G (50% rule, then deductible)");
  it.todo("dragon sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon sword, ench 5, damage 800 G → payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% rule, then deductible)");

  // Multiple items + deductible per damage event
  it.todo("dragon attack on insured sword (500 G) + amulet (300 G) → payout 600 G (deductible per damaged item)");

  // Multiple items of the same type
  it.todo("policy covers two swords → insurance sum 2000, cap 4000; both damaged → each its own deductible");
  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");

  // Cap rules
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("policy with cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
  it.todo("sword cap 2000; two successive claims of 1500 → 1st payout 1400 (cap rem 600), 2nd payout 600 (cap rem 0)");

  // Rounding payout
  it.todo("payout 350.5 G → rounded down to 350 G (MHPCO's favor)");

  // Claim errors
  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr");
  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
});

