const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const policyBase = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type], 0);
  const firstInsurance = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type] * FIRST_INSURANCE_RATE, 0);
  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

