const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number => {
  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items) }));
  return { results };
};

